 {"id":"bd-3e2.2","title":"Implement Rust axum web server (vc_web crate)","description":"## Overview
Build the Rust backend that serves the JSON API for the web dashboard, proxying data from DuckDB.

## Background
The Next.js frontend needs a JSON API to fetch data. This Rust server provides that API, querying DuckDB and formatting responses. It runs alongside the collector daemon.

## Project Structure
```
vc_web/
├── Cargo.toml
└── src/
    ├── lib.rs
    ├── server.rs         # Main server setup
    ├── routes/
    │   ├── mod.rs
    │   ├── overview.rs   # /api/overview
    │   ├── machines.rs   # /api/machines/*
    │   ├── accounts.rs   # /api/accounts/*
    │   ├── sessions.rs   # /api/sessions/*
    │   ├── alerts.rs     # /api/alerts/*
    │   ├── guardian.rs   # /api/guardian/*
    │   └── websocket.rs  # /ws for live updates
    ├── auth.rs           # Optional authentication
    └── error.rs          # Error types
```

## Server Setup
```rust
// src/server.rs
use axum::{
    routing::{get, post},
    Router,
    Extension,
};
use tower_http::cors::CorsLayer;

pub struct WebServer {
    store: Arc<VcStore>,
    config: WebConfig,
}

impl WebServer {
    pub fn new(store: Arc<VcStore>, config: WebConfig) -> Self {
        Self { store, config }
    }

    pub async fn run(&self) -> Result<()> {
        let app = Router::new()
            // Overview
            .route("/api/overview", get(routes::overview::get_overview))

            // Machines
            .route("/api/machines", get(routes::machines::list))
            .route("/api/machines/:id", get(routes::machines::get))
            .route("/api/machines/:id/collectors", get(routes::machines::collectors))

            // Accounts
            .route("/api/accounts", get(routes::accounts::list))
            .route("/api/accounts/:id/usage", get(routes::accounts::usage))

            // Sessions
            .route("/api/sessions", get(routes::sessions::list))
            .route("/api/sessions/:id", get(routes::sessions::get))

            // Alerts
            .route("/api/alerts", get(routes::alerts::list))
            .route("/api/alerts/:id/acknowledge", post(routes::alerts::acknowledge))
            .route("/api/alerts/rules", get(routes::alerts::rules))

            // Guardian
            .route("/api/guardian/status", get(routes::guardian::status))
            .route("/api/guardian/pending", get(routes::guardian::pending))
            .route("/api/guardian/approve/:id", post(routes::guardian::approve))
            .route("/api/guardian/runs", get(routes::guardian::runs))

            // WebSocket for live updates
            .route("/ws", get(routes::websocket::handler))

            // Middleware
            .layer(CorsLayer::permissive())
            .layer(Extension(self.store.clone()));

        let addr = format\!("{}:{}", self.config.host, self.config.port);
        tracing::info\!("Starting web server on {}", addr);

        axum::Server::bind(&addr.parse()?)
            .serve(app.into_make_service())
            .await?;

        Ok(())
    }
}
```

## Route Handlers
```rust
// src/routes/overview.rs
use axum::{Extension, Json};

#[derive(Serialize)]
pub struct Overview {
    active_agents: u32,
    rate_limit_pct: f64,
    active_alerts: u32,
    machines_online: u32,
    machines_total: u32,
    recent_alerts: Vec<AlertSummary>,
    usage_history: Vec<UsagePoint>,
}

pub async fn get_overview(
    Extension(store): Extension<Arc<VcStore>>,
) -> Result<Json<Overview>, AppError> {
    let active_agents = store.query_scalar::<u32>(
        "SELECT COUNT(*) FROM pt_processes WHERE category = \"agent\" AND ended_at IS NULL"
    ).await?;

    let rate_limit_pct = store.query_scalar::<f64>(
        "SELECT MAX(usage_pct) FROM caam_accounts"
    ).await?;

    let active_alerts = store.query_scalar::<u32>(
        "SELECT COUNT(*) FROM alert_history WHERE resolved_at IS NULL"
    ).await?;

    let machines = store.query::<(u32, u32)>(
        "SELECT COUNT(*) FILTER (WHERE status = \"online\"), COUNT(*) FROM machines"
    ).await?;

    let recent_alerts = store.query_vec::<AlertSummary>(
        "SELECT id, severity, title, fired_at FROM alert_history ORDER BY fired_at DESC LIMIT 5"
    ).await?;

    let usage_history = store.query_vec::<UsagePoint>(
        "SELECT date_trunc(\"hour\", ts) as time, AVG(usage_pct) as usage, MAX(limit_pct) as limit
         FROM caut_usage WHERE ts > now() - INTERVAL 24 HOUR GROUP BY 1 ORDER BY 1"
    ).await?;

    Ok(Json(Overview {
        active_agents,
        rate_limit_pct,
        active_alerts,
        machines_online: machines.0,
        machines_total: machines.1,
        recent_alerts,
        usage_history,
    }))
}
```

## WebSocket for Live Updates
```rust
// src/routes/websocket.rs
use axum::extract::ws::{WebSocket, WebSocketUpgrade};
use futures::{SinkExt, StreamExt};

pub async fn handler(
    ws: WebSocketUpgrade,
    Extension(store): Extension<Arc<VcStore>>,
) -> impl IntoResponse {
    ws.on_upgrade(|socket| handle_socket(socket, store))
}

async fn handle_socket(mut socket: WebSocket, store: Arc<VcStore>) {
    let mut interval = tokio::time::interval(Duration::from_secs(5));

    loop {
        interval.tick().await;

        // Send updates
        let update = serde_json::json\!({
            "type": "update",
            "alerts": store.get_active_alerts().await.unwrap_or_default(),
            "machines": store.get_machine_statuses().await.unwrap_or_default(),
        });

        if socket.send(Message::Text(update.to_string())).await.is_err() {
            break;
        }
    }
}
```

