Build Autopilot mode that enables fully autonomous agent fleet operation with intelligent decision-making.

## Background
Autopilot combines Oracle predictions, Guardian remediation, and collected telemetry to make autonomous decisions about agent operation: when to switch accounts, when to pause work, when to scale up/down.

## Autopilot Capabilities

### 1. Preemptive Account Switching
```rust
pub struct AccountAutopilot {
    oracle: Arc<Oracle>,
    caam: Arc<CaamClient>,
    config: AutopilotConfig,
}

impl AccountAutopilot {
    /// Check if we should preemptively switch accounts
    pub async fn check_switch(&self) -> Option<SwitchRecommendation> {
        // Get current account state
        let current = self.caam.current_account().await?;

        // Get Oracle prediction
        let forecast = self.oracle.forecast_rate_limit(
            &current.program,
            &current.account_id,
            Duration::from_mins(30)
        ).await?;

        // If predicted to hit limit soon, recommend switch
        if forecast.will_hit_limit && forecast.time_to_limit < Duration::from_mins(15) {
            let alternatives = self.caam.list_accounts(&current.program).await?
                .into_iter()
                .filter(|a| a.account_id != current.account_id)
                .filter(|a| a.usage_pct < self.config.switch_threshold)
                .collect::<Vec<_>>();

            if let Some(best) = alternatives.first() {
                return Some(SwitchRecommendation {
                    from: current.clone(),
                    to: best.clone(),
                    reason: format!(
                        "Predicted to hit rate limit in {} mins",
                        forecast.time_to_limit.as_mins()
                    ),
                    confidence: forecast.confidence,
                });
            }
        }
        None
    }

    /// Execute account switch if autopilot is enabled
    pub async fn maybe_switch(&self) -> Result<Option<SwitchEvent>> {
        if !self.config.enabled {
            return Ok(None);
        }

        if let Some(rec) = self.check_switch().await {
            if rec.confidence >= self.config.min_confidence {
                self.caam.switch_account(&rec.to.account_id).await?;
                return Ok(Some(SwitchEvent::from_recommendation(rec)));
            }
        }
        Ok(None)
    }
}
```

### 2. Workload Management
```rust
pub struct WorkloadAutopilot {
    store: Arc<VcStore>,
    ntm: Arc<NtmClient>,
    config: AutopilotConfig,
}

impl WorkloadAutopilot {
    /// Balance workload across available agents/machines
    pub async fn balance_workload(&self) -> Result<Vec<BalanceAction>> {
        let mut actions = Vec::new();

        // Get current agent distribution
        let agents = self.store.query_vec::<AgentStatus>(
            "SELECT machine_id, COUNT(*) as agent_count, AVG(cpu_percent) as avg_cpu
             FROM pt_processes WHERE category = \"agent\" AND ended_at IS NULL
             GROUP BY machine_id"
        ).await?;

        // Find overloaded machines
        let overloaded = agents.iter()
            .filter(|a| a.avg_cpu > self.config.cpu_threshold)
            .collect::<Vec<_>>();

        // Find underutilized machines
        let underutilized = agents.iter()
            .filter(|a| a.avg_cpu < self.config.cpu_min_threshold)
            .collect::<Vec<_>>();

        // Recommend migrations
        for over in &overloaded {
            if let Some(under) = underutilized.first() {
                actions.push(BalanceAction::MigrateAgent {
                    from_machine: over.machine_id.clone(),
                    to_machine: under.machine_id.clone(),
                    reason: "Load balancing".into(),
                });
            }
        }

        Ok(actions)
    }
}
```

### 3. Cost Optimization
```rust
pub struct CostAutopilot {
    store: Arc<VcStore>,
    config: AutopilotConfig,
}

impl CostAutopilot {
    /// Analyze spending and suggest optimizations
    pub async fn analyze_costs(&self) -> Result<CostAnalysis> {
        let daily_cost = self.store.query_scalar::<f64>(
            "SELECT SUM(cost_estimate) FROM caut_usage WHERE ts > current_date"
        ).await?;

        let by_model = self.store.query_vec::<ModelCost>(
            "SELECT model, SUM(cost_estimate) as cost, COUNT(*) as requests
             FROM caut_usage WHERE ts > current_date - 7
             GROUP BY model ORDER BY cost DESC"
        ).await?;

        let recommendations = Vec::new();

        // Check for expensive model usage that could use cheaper alternatives
        for model_cost in &by_model {
            if model_cost.model.contains("opus") && model_cost.cost > self.config.opus_daily_limit {
                recommendations.push(CostRecommendation {
                    title: "Consider using Sonnet for routine tasks".into(),
                    potential_savings: model_cost.cost * 0.5,
                    severity: "info".into(),
                });
            }
        }

        Ok(CostAnalysis {
            daily_cost,
            projected_monthly: daily_cost * 30.0,
            by_model,
            recommendations,
        })
    }
}
```

## Autopilot Loop
```rust
pub struct Autopilot {
    account: AccountAutopilot,
    workload: WorkloadAutopilot,
    cost: CostAutopilot,
    config: AutopilotConfig,
}

impl Autopilot {
    pub async fn run_loop(&self) {
        let mut interval = tokio::time::interval(Duration::from_secs(60));

        loop {
            interval.tick().await;

            if !self.config.enabled {
                continue;
            }

            // Account management
            if let Ok(Some(switch)) = self.account.maybe_switch().await {
                tracing::info!("Autopilot switched account: {:?}", switch);
            }

            // Workload balancing (less frequent)
            if self.should_check_workload() {
                if let Ok(actions) = self.workload.balance_workload().await {
                    for action in actions {
                        if self.config.auto_execute_balance {
                            self.execute_balance_action(action).await;
                        }
                    }
                }
            }

            // Cost analysis (hourly)
            if self.should_check_costs() {
                if let Ok(analysis) = self.cost.analyze_costs().await {
                    if analysis.daily_cost > self.config.daily_budget {
                        self.trigger_cost_alert(analysis).await;
                    }
                }
            }
        }
    }
}
```

