    /// Balance workload across available agents/machines
    pub async fn balance_workload(&self) -> Result<Vec<BalanceAction>> {
        let mut actions = Vec::new();

        // Get current agent distribution
        let agents = self.store.query_vec::<AgentStatus>(
            "SELECT machine_id, COUNT(*) as agent_count, AVG(cpu_percent) as avg_cpu
             FROM pt_processes WHERE category = \"agent\" AND ended_at IS NULL
             GROUP BY machine_id"
        ).await?;

        // Find overloaded machines
        let overloaded = agents.iter()
            .filter(|a| a.avg_cpu > self.config.cpu_threshold)
            .collect::<Vec<_>>();

        // Find underutilized machines
        let underutilized = agents.iter()
            .filter(|a| a.avg_cpu < self.config.cpu_min_threshold)
            .collect::<Vec<_>>();

        // Recommend migrations
        for over in &overloaded {
            if let Some(under) = underutilized.first() {
                actions.push(BalanceAction::MigrateAgent {
                    from_machine: over.machine_id.clone(),
                    to_machine: under.machine_id.clone(),
                    reason: "Load balancing".into(),
                });
            }
        }

        Ok(actions)
    }
}
