## DNA Computation
```rust
pub struct DnaComputer {
    store: Arc<VcStore>,
}

impl DnaComputer {
    /// Compute DNA for an agent configuration
    pub async fn compute_dna(
        &self,
        program: &str,
        model: &str,
        config_hash: Option<&str>,
        time_range: TimeRange,
    ) -> Result<AgentDna> {
        let filter = format\!(
            "program = \"{}\" AND model = \"{}\"",
            program, model
        );

        // Token patterns
        let token_stats = self.store.query_one::<TokenStats>(&format\!(r#"
            SELECT 
                AVG(tokens_out) as avg_tokens,
                AVG(tokens_in::FLOAT / NULLIF(tokens_out, 0)) as input_output_ratio,
                STDDEV(tokens_out) as token_variance
            FROM caut_usage
            WHERE {}
              AND ts BETWEEN ? AND ?
        "#, filter)).bind(time_range.start).bind(time_range.end).await?;

        // Error patterns
        let error_stats = self.store.query_one::<ErrorStats>(&format\!(r#"
            SELECT
                COUNT(*) FILTER (WHERE error IS NOT NULL)::FLOAT / COUNT(*) as error_rate,
                COUNT(*) FILTER (WHERE error IS NOT NULL AND next_success) / 
                    NULLIF(COUNT(*) FILTER (WHERE error IS NOT NULL), 0) as recovery_rate
            FROM caut_usage
            WHERE {}
        "#, filter)).await?;

        // Tool preferences (from session analysis)
        let tool_prefs = self.store.query_vec::<ToolPref>(&format\!(r#"
            SELECT tool_name, 
                   COUNT(*)::FLOAT / SUM(COUNT(*)) OVER () as preference,
                   AVG(CASE WHEN success THEN 1.0 ELSE 0.0 END) as success_rate
            FROM session_tool_usage
            WHERE {}
            GROUP BY tool_name
        "#, filter)).await?;

        // Timing patterns
        let timing = self.store.query_one::<TimingStats>(&format\!(r#"
            SELECT
                AVG(response_time_ms) as avg_response,
                PERCENTILE_CONT(0.95) WITHIN GROUP (ORDER BY response_time_ms) as p95
            FROM caut_usage
            WHERE {}
        "#, filter)).await?;

        // Combine into DNA
        let dna = AgentDna {
            dna_id: format\!("{}:{}:{}", program, model, config_hash.unwrap_or("default")),
            agent_program: program.to_string(),
            agent_model: model.to_string(),
            configuration_hash: config_hash.map(String::from),
            avg_tokens_per_turn: token_stats.avg_tokens,
            avg_input_output_ratio: token_stats.input_output_ratio,
            error_rate: error_stats.error_rate,
            recovery_rate: error_stats.recovery_rate,
            tool_preferences: tool_prefs.into_iter()
                .map(|t| (t.tool_name, t.preference))
                .collect(),
            avg_response_time_ms: timing.avg_response,
            p95_response_time_ms: timing.p95,
            // ... more fields
            computed_at: Utc::now(),
        };

        // Compute embedding for similarity
        let dna = self.compute_embedding(dna).await?;

        // Store DNA
        self.store.upsert_dna(&dna).await?;

        // Track history
        self.store.insert_dna_history(&dna).await?;

        Ok(dna)
    }
}
