## Anomaly Detection
```rust
impl DnaComputer {
    /// Detect anomalies in recent agent behavior
    pub async fn detect_anomalies(&self, dna_id: &str) -> Result<Vec<Anomaly>> {
        let current = self.store.get_dna(dna_id).await?;
        let history = self.store.get_dna_history(dna_id, 30).await?;  // Last 30 snapshots

        let mut anomalies = Vec::new();

        // Check each metric against historical baseline
        let historical_error_rate: Vec<f64> = history.iter()
            .map(|h| h.metrics.error_rate)
            .collect();
        let (mean, stddev) = stats::mean_stddev(&historical_error_rate);

        if (current.error_rate - mean).abs() > 2.0 * stddev {
            anomalies.push(Anomaly {
                metric: "error_rate".into(),
                current: current.error_rate,
                expected: mean,
                deviation_sigmas: (current.error_rate - mean) / stddev,
                severity: if (current.error_rate - mean) / stddev > 3.0 { "high" } else { "medium" }.into(),
            });
        }

        // Similar checks for other metrics...

        Ok(anomalies)
    }
}
